        {ls==="idle"&&!lm&&<div style={{fontSize:10,color:K.dim,marginTop:-10,marginBottom:10,lineHeight:1.5,fontFamily:fm}}>US: AAPL · Canada: RY.TO · UK: VOD.L · Germany: SAP.DE</div>}
