      if(valItems.length>0){html+='<div class="fc"><div class="fch">Valuation &amp; Returns</div>';valItems.forEach(function(x){html+='<div class="fr"><span class="fk">'+x[1]+'</span><span class="fv">'+x[0]+'</span></div>'});html+='</div>'}
